# On-Chain Narrative Radar
# 动量驱动 · 链上新币发现
# 覆盖 ETH/SOL/BSC/Base

import requests
import time
from datetime import datetime

CHAIN_ENDPOINTS = {
    'ethereum': 'https://api.dexscreener.com/latest/dex/pairs/ethereum',
    'solana': 'https://api.dexscreener.com/latest/dex/pairs/solana',
    'bsc': 'https://api.dexscreener.com/latest/dex/pairs/bsc',
    'base': 'https://api.dexscreener.com/latest/dex/pairs/base',
}

NARRATIVE_KEYWORDS = {
    'musk': '★★★ 马斯克叙事',
    'trump': '★★★ 川普叙事',
    'binance': '★★ 币安叙事',
    'cz': '★★ CZ叙事',
}

def scan_chain(chain):
    url = CHAIN_ENDPOINTS.get(chain)
    try:
        resp = requests.get(url, timeout=10)
        pairs = resp.json().get('pairs', [])[:20]
        results = []
        for p in pairs:
            mc = float(p.get('marketCap', 0))
            if mc < 10_000 or mc > 50_000_000:
                continue
            # 检测3轮连涨
            tx_count = p.get('txns', {})
            buys = tx_count.get('h24', {}).get('buys', 0)
            sells = tx_count.get('h24', {}).get('sells', 0)
            if buys > sells * 2 and buys > 50:
                results.append(p)
        return results
    except Exception as e:
        print(f'Error scanning {chain}: {e}')
        return []

def run():
    while True:
        for chain in CHAIN_ENDPOINTS:
            results = scan_chain(chain)
            for r in results:
                print(f"[{chain.upper()}] {r['baseToken']['symbol']} | MC: ${r['marketCap']:,.0f}")
        time.sleep(30)

if __name__ == '__main__':
    run()

# OI + Funding Rate Scanner
# 费率正转负 + OI 放大检测

import requests
import time

BINANCE_API = 'https://fapi.binance.com'
PREV_STATE = {}

def get_funding_and_oi(symbol):
    symbol = symbol.upper().replace('-USDT-SWAP', 'USDT').replace('-', '')
    fr_url = f"{BINANCE_API}/fapi/v1/premiumIndex?symbol={symbol}"
    oi_url = f"{BINANCE_API}/futures/data/openInterestHist?symbol={symbol}&period=5m&limit=2"
    try:
        fr = requests.get(fr_url, timeout=5).json()
        oi = requests.get(oi_url, timeout=5).json()
        return {
            'fundingRate': float(fr.get('lastFundingRate', 0)) * 100,
            'oi': float(oi[-1]['sumOpenInterestValue']) if oi else 0
        }
    except:
        return None

def check_flip(symbol):
    curr = get_funding_and_oi(symbol)
    prev = PREV_STATE.get(symbol, {})
    if not curr or not prev:
        PREV_STATE[symbol] = curr
        return
    was_positive = prev['fundingRate'] > 0
    is_negative = curr['fundingRate'] < 0
    oi_rising = curr['oi'] > prev['oi'] * 1.05
    if was_positive and is_negative and oi_rising:
        print(f"[信号] {symbol} 费率转负 + OI放大 → 做多信号")
    PREV_STATE[symbol] = curr

def run():
    tickers = requests.get(f"{BINANCE_API}/fapi/v1/ticker/24hr", timeout=5).json()
    usdt = [t for t in tickers if t['symbol'].endswith('USDT')][:50]
    for t in usdt:
        check_flip(t['symbol'])
    time.sleep(300)

if __name__ == '__main__':
    run()

# Futures + Alpha Autonomous Trading v1
# AI 独立完成 扫描→分析→虚拟开仓→盯盘→平仓→复盘

import requests
import time
import json
from datetime import datetime

BINANCE_API = 'https://fapi.binance.com'
STATE_FILE = 'trading_state.json'

LEVERAGE = 3
POSITION_PCT = 30
MAX_OPEN = 3
COOLDOWN_HOURS = 2

def get_balance():
    # 获取账户余额（模拟）
    return 100.0

def get_all_tickers():
    url = f"{BINANCE_API}/fapi/v1/ticker/24hr"
    return requests.get(url, timeout=10).json()

def get_funding_rates():
    url = f"{BINANCE_API}/fapi/v1/premiumIndex"
    data = requests.get(url, timeout=10).json()
    return {d['symbol']: float(d['lastFundingRate']) * 100 for d in data}

def detect_extreme_negative_funding(symbol, fr):
    """费率极端深负 → 做多逼空"""
    if fr < -0.1:
        return {'type': 'neg_funding', 'direction': 'long', 'strength': 'S'}
    return None

def detect_extreme_positive_funding(symbol, fr):
    """费率极端正 → 做空"""
    if fr > 0.1:
        return {'type': 'pos_funding', 'direction': 'short', 'strength': 'S'}
    return None

def scan():
    tickers = get_all_tickers()
    funding = get_funding_rates()
    candidates = [t for t in tickers if t['symbol'].endswith('USDT')][:100]

    for t in candidates:
        symbol = t['symbol']
        fr = funding.get(symbol, 0)
        sig = detect_extreme_negative_funding(symbol, fr) or detect_extreme_positive_funding(symbol, fr)
        if sig:
            price = float(t['lastPrice'])
            print(f"[信号] {symbol} {sig['direction']} @ {price} | 费率 {fr:+.3f}%")
            return symbol, sig, price
    return None

if __name__ == '__main__':
    while True:
        result = scan()
        if result:
            print(f"开仓信号: {result}")
        time.sleep(30)

if __name__ == '__main__':
    run()

# Binance Alpha Monitor
# WebSocket + AI 分析 + Telegram 推送

import websocket
import json
import requests
import time

BINANCE_WS = 'wss://stream.binance.com:9443/ws/!miniTicker@arr'
TELEGRAM_API = 'https://api.telegram.org/bot<YOUR_BOT>/sendMessage'

PREVIOUS_ALPHA = set()

def on_message(ws, message):
    data = json.loads(message)
    for ticker in data:
        symbol = ticker['s']
        # 检测新上线的小币
        if symbol.endswith('USDT') and float(ticker['c']) < 0.01:
            if symbol not in PREVIOUS_ALPHA:
                PREVIOUS_ALPHA.add(symbol)
                print(f"[新币] {symbol} 上线通知")
                send_telegram(f"🚨 新币上线: {symbol}")

def send_telegram(msg):
    try:
        requests.post(TELEGRAM_API, json={'chat_id': '<CHAT_ID>', 'text': msg})
    except:
        pass

def run():
    ws = websocket.WebSocketApp(BINANCE_WS, on_message=on_message)
    ws.run_forever()

if __name__ == '__main__':
    run()
